/**
 * AI Routing Stage
 *
 * Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
 * based on confidence scores from multi-label selection. Routes high-confidence emails directly
 * to final decision while sending uncertain cases through AI classification for enhancement.
 *
 * ROUTING DECISION LOGIC:
 * - High Confidence (>=15): Skip AI - rule-based results are reliable
 * - Medium Confidence (8-14): Route to AI - can benefit from enhanced classification
 * - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
 * - No Labels Selected: Route to AI - last chance for classification
 * - Hard Assertions: Skip AI - domain-based results are authoritative
 */

import { EmailMessage, ClassificationSession } from '../types';
import { ClassificationResult, SelectedLabel, CandidateScore } from '../types/classification-result';
import { ConfidenceThresholds } from './types';
import {
  validateEmailInput,
  validateSessionInput,
  validateConfigInput,
  validateConfidenceScore,
} from '../utils/validation';

// Configuration interface
export interface AIRoutingConfig {
  settings: {
    aiRouting: {
      highConfidenceThreshold: number;
      aiRequiredThreshold: number;
      skipAiConditions: string[];
    };
  };
  confidenceThresholds: ConfidenceThresholds & {
    aiClassificationRequired?: number;
  };
}

// Routing decision result
export interface RoutingDecision {
  routeToAi: boolean;
  routingReason: string;
  confidenceAssessment: string;
  costConsideration: string;
}

// Simplified explainability trace for AI routing
export interface AIRoutingExplainabilityTrace {
  stageType: string;
  stageOrder: number;
  decisionFactors: {
    primaryScore: number;
    thresholdAnalysis: {
      highConfidenceThreshold: number;
      aiRequiredThreshold: number;
      lowConfidenceThreshold: number;
      primaryScore: number;
      thresholdMet: string;
    };
    competitorAnalysis: {
      closeCompetitorsFound: boolean;
      competitorCount: number;
      multipleLabelsSelected: boolean;
    };
  };
  reasoning: string;
  processingMetadata: {
    processingTimeMs: number;
    inputLabelsCount: number;
    candidateScoresCount: number;
  };
}

// Stage result interface
export interface AIRoutingResult {
  routingDecision: RoutingDecision;
  routingBranch: 'aiClassification' | 'directToMerge';
  explainabilityTrace: AIRoutingExplainabilityTrace;
}

/**
 * AI Routing Stage Implementation
 *
 * Analyzes classification confidence and determines optimal routing strategy
 * for email processing continuation.
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => void
 * Mutates result.needsAiClassification and adds explainability trace
 */
export function aiRoutingStage(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AIRoutingConfig
): void {
  const startTime = Date.now();

  // Validate inputs
  validateInputs(email, session, result, config);

  // Extract data from result object
  const selectedLabels = result.selectedLabels;
  const candidateScores = result.candidateScores;

  // Extract routing thresholds with fallbacks
  const highConfidenceThreshold =
    config.settings.aiRouting.highConfidenceThreshold || config.confidenceThresholds.highConfidence || 15;

  const aiRequiredThreshold = config.confidenceThresholds.mediumConfidence || 8;

  const lowConfidenceThreshold = config.confidenceThresholds.lowConfidence || 3;

  const skipAiConditions = config.settings.aiRouting.skipAiConditions || [];

  // Make routing decision
  const routingDecision = makeRoutingDecision(
    selectedLabels,
    candidateScores,
    highConfidenceThreshold,
    aiRequiredThreshold,
    lowConfidenceThreshold,
    skipAiConditions
  );

  // Generate explainability trace
  const explainabilityTrace = generateExplainabilityTrace(
    selectedLabels,
    candidateScores,
    routingDecision,
    {
      highConfidenceThreshold: highConfidenceThreshold,
      aiRequiredThreshold:
        config.settings.aiRouting.aiRequiredThreshold || config.confidenceThresholds.aiClassificationRequired || 12,
      lowConfidenceThreshold: lowConfidenceThreshold,
    },
    startTime
  );

  // Mutate result in place
  result.needsAiClassification = routingDecision.routeToAi;

  // Initialize explainabilityTrace if not exists (defensive check)
  if (!result.explainabilityTrace) {
    throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
  }

  // Add explainability trace to result - store in appropriate field
  if (!result.explainabilityTrace.aiRouting) {
    result.explainabilityTrace.aiRouting = {
      routingDecision: routingDecision.routeToAi ? 'fullClassification' : 'skipAi',
      highConfidenceThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.highConfidenceThreshold,
      aiRequiredThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.aiRequiredThreshold,
      skipConditions: [],
      reason: routingDecision.routingReason,
    };
  }

  // Track processing time
  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
  result.explainabilityTrace.stageTimings['aiRouting'] = explainabilityTrace.processingMetadata.processingTimeMs;
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AIRoutingConfig
): void {
  validateEmailInput(email);
  validateSessionInput(session);
  validateConfigInput(config);

  if (!result) {
    throw new Error('Classification result is required');
  }

  if (!result.selectedLabels) {
    throw new Error('Selected labels are required in result');
  }

  if (!result.candidateScores) {
    throw new Error('Candidate scores are required in result');
  }

  // Validate confidence scores
  for (const label of result.selectedLabels) {
    validateConfidenceScore(label.confidence);
  }
}

/**
 * Core routing decision logic
 */
function makeRoutingDecision(
  selectedLabels: SelectedLabel[],
  candidateScores: Record<string, CandidateScore>,
  highConfidenceThreshold: number,
  aiRequiredThreshold: number,
  lowConfidenceThreshold: number,
  skipAiConditions: string[]
): RoutingDecision {
  // Case 1: No labels selected - route to AI for last chance classification
  if (selectedLabels.length === 0) {
    return {
      routeToAi: true,
      routingReason: 'No labels selected - AI classification may recover classification',
      confidenceAssessment: 'noClassification',
      costConsideration: 'recoveryAttempt',
    };
  }

  // Case 2: Check for hard assertions (skip AI condition)
  if (skipAiConditions.includes('hardAssertion')) {
    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hardAssertion);
    if (hasHardAssertion) {
      return {
        routeToAi: false,
        routingReason: 'hard assertion applied - domain-based classification is authoritative',
        confidenceAssessment: 'hardAssertionSkip',
        costConsideration: 'aiUnnecessary',
      };
    }
  }

  // Case 3: Check primary label confidence
  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  const primaryScore = primaryLabel.confidence;

  // High confidence - skip AI (rule-based results are reliable)
  if (primaryScore >= highConfidenceThreshold) {
    return {
      routeToAi: false,
      routingReason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
      confidenceAssessment: 'highConfidence',
      costConsideration: 'aiUnnecessary',
    };
  }

  // Very low confidence - skip AI (likely unclassifiable)
  if (primaryScore < lowConfidenceThreshold) {
    return {
      routeToAi: false,
      routingReason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
      confidenceAssessment: 'veryLowConfidence',
      costConsideration: 'aiIneffective',
    };
  }

  // Medium confidence range - analyze further for AI routing decision
  const hasMultipleLabels = selectedLabels.length > 1;
  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);

  // Route to AI if in uncertain range and conditions suggest AI could help
  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
    let costConsideration = 'beneficialEnhancement';

    // Additional factors for AI routing decision (prioritize multiple labels over close competitors)
    if (hasCloseCompetitors) {
      aiRoutingReason += ' with close competing categories';
      costConsideration = 'disambiguationValuable';
    }

    if (hasMultipleLabels) {
      aiRoutingReason += ' with multiple labels selected';
      costConsideration = 'multiLabelValidation';
    }

    // Conservative approach: medium confidence usually benefits from AI
    if (primaryScore >= aiRequiredThreshold) {
      return {
        routeToAi: true,
        routingReason: aiRoutingReason + ' - AI classification can improve accuracy',
        confidenceAssessment: 'mediumConfidence',
        costConsideration: costConsideration,
      };
    } else {
      return {
        routeToAi: false,
        routingReason: aiRoutingReason + ' but below AI routing threshold - accept rule-based result',
        confidenceAssessment: 'lowMediumConfidence',
        costConsideration: 'costThresholdNotMet',
      };
    }
  }

  // Default case (shouldn't reach here with proper thresholds)
  return {
    routeToAi: false,
    routingReason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
    confidenceAssessment: 'unclear',
    costConsideration: 'defaultConservative',
  };
}

/**
 * Check if there are close competing categories that AI could help disambiguate
 */
function checkCloseCompetitors(
  candidateScores: Record<string, CandidateScore>,
  primaryScore: number,
  competitorGap: number = 3
): boolean {
  const competitors = Object.entries(candidateScores)
    .map(([categoryCode, scoreData]) => ({
      category: categoryCode,
      score: scoreData.score || 0,
    }))
    .filter((cat) => cat.score > 0 && cat.score < primaryScore)
    .filter((cat) => primaryScore - cat.score <= competitorGap);

  return competitors.length > 0;
}

/**
 * Generate comprehensive explainability trace
 */
function generateExplainabilityTrace(
  selectedLabels: SelectedLabel[],
  candidateScores: Record<string, CandidateScore>,
  routingDecision: RoutingDecision,
  thresholds: {
    highConfidenceThreshold: number;
    aiRequiredThreshold: number;
    lowConfidenceThreshold: number;
  },
  startTime: number
): AIRoutingExplainabilityTrace {
  const processingTime = Date.now() - startTime;
  const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];

  return {
    stageType: 'aiRouting',
    stageOrder: 8,
    decisionFactors: {
      primaryScore: primaryLabel?.confidence || 0,
      thresholdAnalysis: {
        highConfidenceThreshold: thresholds.highConfidenceThreshold,
        aiRequiredThreshold: thresholds.aiRequiredThreshold,
        lowConfidenceThreshold: thresholds.lowConfidenceThreshold,
        primaryScore: primaryLabel?.confidence || 0,
        thresholdMet: primaryLabel?.confidence >= thresholds.aiRequiredThreshold ? 'aiRequired' : 'belowThreshold',
      },
      competitorAnalysis: {
        closeCompetitorsFound: checkCloseCompetitors(candidateScores, primaryLabel?.confidence || 0),
        competitorCount: Object.keys(candidateScores).length - 1,
        multipleLabelsSelected: selectedLabels.length > 1,
      },
    },
    reasoning: routingDecision.routingReason,
    processingMetadata: {
      processingTimeMs: processingTime,
      inputLabelsCount: selectedLabels.length,
      candidateScoresCount: Object.keys(candidateScores).length,
    },
  };
}

