     1→import { CategoryConfiguration, validateCategoryConfiguration, getValidationErrors } from './category-config-schema';
     2→import {
     3→  ProcessingConfigTuning,
     4→  validateProcessingConfigTuning,
     5→  getProcessingConfigErrors,
     6→} from './processing-config-schema';
     7→
     8→/**
     9→ * Configuration validation service
    10→ * Provides comprehensive validation for all configuration types
    11→ */
    12→
    13→export interface ValidationResult {
    14→  isValid: boolean;
    15→  errors: ValidationError[];
    16→  warnings: ValidationWarning[];
    17→  performance: ValidationPerformance;
    18→  summary: ValidationSummary;
    19→}
    20→
    21→export interface ValidationError {
    22→  code: string;
    23→  message: string;
    24→  path: string;
    25→  severity: 'error' | 'warning';
    26→  category: 'schema' | 'logic' | 'reference' | 'performance' | 'security';
    27→  suggestion?: string;
    28→}
    29→
    30→export interface ValidationWarning {
    31→  code: string;
    32→  message: string;
    33→  path: string;
    34→  impact: 'low' | 'medium' | 'high';
    35→  recommendation: string;
    36→}
    37→
    38→export interface ValidationPerformance {
    39→  validationTimeMs: number;
    40→  rulesChecked: number;
    41→  attributesValidated: number;
    42→  crossReferencesChecked: number;
    43→}
    44→
    45→export interface ValidationSummary {
    46→  totalErrors: number;
    47→  totalWarnings: number;
    48→  criticalIssues: number;
    49→  configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
    50→  recommendedActions: string[];
    51→}
    52→
    53→export interface CrossReferenceCheck {
    54→  attributeReferences: string[];
    55→  domainReferences: string[];
    56→  categoryReferences: string[];
    57→  orphanedReferences: string[];
    58→}
    59→
    60→export interface ValidationOptions {
    61→  skipCrossReferences?: boolean;
    62→  skipPerformanceChecks?: boolean;
    63→  skipSecurityChecks?: boolean;
    64→  skipQualityChecks?: boolean;
    65→  strictMode?: boolean;
    66→}
    67→
    68→export class ConfigurationValidator {
    69→  constructor() {
    70→    // No initialization needed
    71→  }
    72→
    73→  /**
    74→   * Validate category configuration with comprehensive checks
    75→   */
    76→  async validateCategoryConfiguration(
    77→    config: CategoryConfiguration | unknown,
    78→    _options: ValidationOptions = {}
    79→  ): Promise<ValidationResult> {
    80→    const startTime = Date.now();
    81→    const errors: ValidationError[] = [];
    82→    const warnings: ValidationWarning[] = [];
    83→
    84→    let validatedConfig: CategoryConfiguration | undefined;
    85→
    86→    // Schema validation
    87→    try {
    88→      if (typeof config === 'object' && config !== null && 'processingConfig' in config) {
    89→        validatedConfig = config as CategoryConfiguration;
    90→        validateCategoryConfiguration(config);
    91→      } else {
    92→        validatedConfig = validateCategoryConfiguration(config);
    93→      }
    94→    } catch {
    95→      // Schema validation failed, but continue with logic checks for comprehensive error reporting
    96→      const schemaErrors = getValidationErrors(config);
    97→      errors.push(...schemaErrors.map((err) => this.parseValidationError(err)));
    98→
    99→      // Try to use the config as-is for additional validation checks
   100→      if (typeof config === 'object' && config !== null && 'processingConfig' in config) {
   101→        validatedConfig = config as CategoryConfiguration;
   102→      }
   103→    }
   104→
   105→    // Initialize cross-reference result
   106→    let crossRefResult: { errors: ValidationError[]; warnings: ValidationWarning[]; totalChecks: number } = {
   107→      errors: [],
   108→      warnings: [],
   109→      totalChecks: 0,
   110→    };
   111→
   112→    // Only run additional checks if we have a minimally valid config structure
   113→    if (validatedConfig && validatedConfig.processingConfig) {
   114→      // Logic validation
   115→      const logicErrors = await this.validateConfigurationLogic(validatedConfig);
   116→      errors.push(...logicErrors);
   117→
   118→      // Rule conflict detection
   119→      const ruleConflictErrors = this.detectRuleConflicts(validatedConfig);
   120→      errors.push(...ruleConflictErrors);
   121→
   122→      // Attribute matrix validation
   123→      const attributeMatrixErrors = this.validateAttributeMatrix(validatedConfig);
   124→      errors.push(...attributeMatrixErrors);
   125→
   126→      // Cross-reference validation
   127→      crossRefResult = await this.validateCrossReferences(validatedConfig);
   128→      errors.push(...crossRefResult.errors);
   129→      warnings.push(...crossRefResult.warnings);
   130→
   131→      // Performance validation
   132→      const perfResult = await this.validatePerformanceSettings(validatedConfig);
   133→      warnings.push(...perfResult.warnings);
   134→
   135→      // Security validation
   136→      const securityResult = await this.validateSecuritySettings(validatedConfig);
   137→      errors.push(...securityResult.errors);
   138→      warnings.push(...securityResult.warnings);
   139→
   140→      // Configuration quality checks
   141→      const qualityWarnings = await this.validateConfigurationQuality(validatedConfig);
   142→      warnings.push(...qualityWarnings);
   143→    }
   144→
   145→    const performance = {
   146→      validationTimeMs: Date.now() - startTime,
   147→      rulesChecked: validatedConfig ? this.countRules(validatedConfig) : 0,
   148→      attributesValidated: validatedConfig?.processingConfig?.attributes?.schema
   149→        ? Object.keys(validatedConfig.processingConfig.attributes.schema).length
   150→        : 0,
   151→      crossReferencesChecked: validatedConfig ? crossRefResult.totalChecks : 0,
   152→    };
   153→
   154→    return this.buildValidationResult(
   155→      startTime,
   156→      errors,
   157→      warnings,
   158→      performance.rulesChecked,
   159→      performance.attributesValidated,
   160→      performance.crossReferencesChecked
   161→    );
   162→  }
   163→
   164→  /**
   165→   * Validate processing configuration tuning parameters
   166→   */
   167→  async validateProcessingConfigurationTuning(
   168→    config: ProcessingConfigTuning | unknown,
   169→    _options: ValidationOptions = {}
   170→  ): Promise<ValidationResult> {
   171→    const startTime = Date.now();
   172→    const errors: ValidationError[] = [];
   173→    const warnings: ValidationWarning[] = [];
   174→
   175→    let validatedConfig: ProcessingConfigTuning;
   176→
   177→    // Schema validation
   178→    try {
   179→      validatedConfig = validateProcessingConfigTuning(config);
   180→    } catch (error) {
   181→      console.error('Processing configuration schema validation failed:', error);
   182→      const schemaErrors = getProcessingConfigErrors(config);
   183→      errors.push(
   184→        ...schemaErrors.map((err) => ({
   185→          code: 'PROCESSING_SCHEMA_VALIDATION_FAILED',
   186→          message: err,
   187→          path: 'root',
   188→          severity: 'error' as const,
   189→          category: 'schema' as const,
   190→          suggestion: 'Check the processing configuration structure against the schema',
   191→        }))
   192→      );
   193→
   194→      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
   195→    }
   196→
   197→    // Tuning parameter validation
   198→    const tuningErrors = await this.validateTuningParameters(validatedConfig);
   199→    errors.push(...tuningErrors.errors);
   200→    warnings.push(...tuningErrors.warnings);
   201→
   202→    // Performance consistency validation
   203→    const consistencyWarnings = await this.validatePerformanceConsistency(validatedConfig);
   204→    warnings.push(...consistencyWarnings);
   205→
   206→    const performance = {
   207→      validationTimeMs: Date.now() - startTime,
   208→      rulesChecked: 0,
   209→      attributesValidated: 0,
   210→      crossReferencesChecked: 0,
   211→    };
   212→
   213→    return this.buildValidationResult(
   214→      startTime,
   215→      errors,
   216→      warnings,
   217→      performance.rulesChecked,
   218→      performance.attributesValidated,
   219→      performance.crossReferencesChecked
   220→    );
   221→  }
   222→
   223→  /**
   224→   * Validate domain sources configuration
   225→   */
   226→  async validateDomainSources(
   227→    config: Record<string, string[]> | unknown,
   228→    _options: ValidationOptions = {}
   229→  ): Promise<ValidationResult> {
   230→    const startTime = Date.now();
   231→    const errors: ValidationError[] = [];
   232→    const warnings: ValidationWarning[] = [];
   233→
   234→    if (!config || typeof config !== 'object') {
   235→      errors.push({
   236→        code: 'INVALID_DOMAIN_SOURCES_TYPE',
   237→        message: 'Domain sources must be an object',
   238→        path: 'root',
   239→        severity: 'error',
   240→        category: 'schema',
   241→      });
   242→      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
   243→    }
   244→
   245→    const domainSources = config as Record<string, string[]>;
   246→
   247→    // Validate domain groups
   248→    for (const [groupName, domains] of Object.entries(domainSources)) {
   249→      if (!Array.isArray(domains)) {
   250→        errors.push({
   251→          code: 'INVALID_DOMAIN_GROUP_TYPE',
   252→          message: `Domain group "${groupName}" must be an array`,
   253→          path: groupName,
   254→          severity: 'error',
   255→          category: 'schema',
   256→        });
   257→        continue;
   258→      }
   259→
   260→      // Validate individual domains
   261→      for (let i = 0; i < domains.length; i++) {
   262→        const domain = domains[i];
   263→        if (typeof domain !== 'string') {
   264→          errors.push({
   265→            code: 'INVALID_DOMAIN_TYPE',
   266→            message: `Domain at index ${i} in group "${groupName}" must be a string`,
   267→            path: `${groupName}[${i}]`,
   268→            severity: 'error',
   269→            category: 'schema',
   270→          });
   271→          continue;
   272→        }
   273→
   274→        // Validate domain format
   275→        if (!/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(domain)) {
   276→          errors.push({
   277→            code: 'INVALID_DOMAIN_FORMAT',
   278→            message: `Invalid domain format: "${domain}" in group "${groupName}"`,
   279→            path: `${groupName}[${i}]`,
   280→            severity: 'error',
   281→            category: 'logic',
   282→            suggestion: 'Use valid domain format like "example.com"',
   283→          });
   284→        }
   285→      }
   286→
   287→      // Check for duplicate domains within group
   288→      const uniqueDomains = new Set(domains);
   289→      if (uniqueDomains.size !== domains.length) {
   290→        warnings.push({
   291→          code: 'DUPLICATE_DOMAINS_IN_GROUP',
   292→          message: `Group "${groupName}" contains duplicate domains`,
   293→          path: groupName,
   294→          impact: 'low',
   295→          recommendation: 'Remove duplicate domains to improve configuration clarity',
   296→        });
   297→      }
   298→    }
   299→
   300→    // Check for domains appearing in multiple groups
   301→    const allDomains = new Map<string, string[]>();
   302→    for (const [groupName, domains] of Object.entries(domainSources)) {
   303→      for (const domain of domains) {
   304→        if (!allDomains.has(domain)) {
   305→          allDomains.set(domain, []);
   306→        }
   307→        allDomains.get(domain)!.push(groupName);
   308→      }
   309→    }
   310→
   311→    for (const [domain, groups] of Array.from(allDomains.entries())) {
   312→      if (groups.length > 1) {
   313→        warnings.push({
   314→          code: 'DOMAIN_IN_MULTIPLE_GROUPS',
   315→          message: `Domain "${domain}" appears in multiple groups: ${groups.join(', ')}`,
   316→          path: 'cross-reference',
   317→          impact: 'medium',
   318→          recommendation: 'Consider if this domain should only be in one group for clarity',
   319→        });
   320→      }
   321→    }
   322→
   323→    return this.buildValidationResult(startTime, errors, warnings, 0, 0, allDomains.size);
   324→  }
   325→
   326→  /**
   327→   * Validate complete configuration suite (category + processing + domains)
   328→   */
   329→  async validateCompleteConfiguration(
   330→    categoryConfig: CategoryConfiguration,
   331→    processingConfig: ProcessingConfigTuning,
   332→    domainSources: Record<string, string[]>,
   333→    options: ValidationOptions = {}
   334→  ): Promise<ValidationResult> {
   335→    const startTime = Date.now();
   336→    const errors: ValidationError[] = [];
   337→    const warnings: ValidationWarning[] = [];
   338→
   339→    // Validate individual configurations
   340→    const categoryResult = await this.validateCategoryConfiguration(categoryConfig, options);
   341→    const processingResult = await this.validateProcessingConfigurationTuning(processingConfig, options);
   342→    const domainResult = await this.validateDomainSources(domainSources, options);
   343→
   344→    errors.push(...categoryResult.errors, ...processingResult.errors, ...domainResult.errors);
   345→    warnings.push(...categoryResult.warnings, ...processingResult.warnings, ...domainResult.warnings);
   346→
   347→    // Cross-configuration validation
   348→    const crossConfigErrors = await this.validateCrossConfigurationReferences(categoryConfig, domainSources);
   349→    errors.push(...crossConfigErrors);
   350→
   351→    const totalChecks =
   352→      categoryResult.performance.crossReferencesChecked +
   353→      processingResult.performance.crossReferencesChecked +
   354→      domainResult.performance.crossReferencesChecked;
   355→
   356→    return this.buildValidationResult(
   357→      startTime,
   358→      errors,
   359→      warnings,
   360→      categoryResult.performance.rulesChecked,
   361→      categoryResult.performance.attributesValidated,
   362→      totalChecks
   363→    );
   364→  }
   365→
   366→  // Private validation methods
   367→
   368→  private async validateConfigurationLogic(config: CategoryConfiguration): Promise<ValidationError[]> {
   369→    const errors: ValidationError[] = [];
   370→
   371→    // Skip if topLevelCategories is not defined
   372→    if (!config.processingConfig?.topLevelCategories) {
   373→      return errors;
   374→    }
   375→
   376→    // Validate category consistency
   377→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   378→      // Validate subtypes
   379→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   380→        if (subtype.derived && !subtype.derivationLogic) {
   381→          errors.push({
   382→            code: 'MISSING_DERIVATION_LOGIC',
   383→            message: `Derived subtype "${categoryName}.${subtypeName}" has no derivation logic`,
   384→            path: `topLevelCategories.${categoryName}.subtypes.${subtypeName}`,
   385→            severity: 'error',
   386→            category: 'logic',
   387→            suggestion: 'Add derivationLogic or set derived to false',
   388→          });
   389→        }
   390→      }
   391→    }
   392→
   393→    return errors;
   394→  }
   395→
   396→  private async validateCrossReferences(config: CategoryConfiguration): Promise<{
   397→    errors: ValidationError[];
   398→    warnings: ValidationWarning[];
   399→    totalChecks: number;
   400→  }> {
   401→    const errors: ValidationError[] = [];
   402→    const warnings: ValidationWarning[] = [];
   403→    let totalChecks = 0;
   404→
   405→    // Skip if attributes or relevance matrix is not defined
   406→    if (!config.processingConfig?.attributes?.schema || !config.processingConfig?.attributeRelevance) {
   407→      return { errors, warnings, totalChecks };
   408→    }
   409→
   410→    // Get defined attributes
   411→    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));
   412→
   413→    // Check attribute references in relevance matrix
   414→    for (const [categoryName, categoryConfig] of Object.entries(config.processingConfig.attributeRelevance)) {
   415→      if (categoryName === '_roles_legend') continue;
   416→
   417→      totalChecks++;
   418→
   419→      // Type guard to ensure we have the correct structure
   420→      if (
   421→        typeof categoryConfig === 'object' &&
   422→        categoryConfig !== null &&
   423→        'categoryRoles' in categoryConfig &&
   424→        categoryConfig.categoryRoles
   425→      ) {
   426→        for (const attributeName of Object.keys(categoryConfig.categoryRoles)) {
   427→          totalChecks++;
   428→          if (!definedAttributes.has(attributeName)) {
   429→            errors.push({
   430→              code: 'UNDEFINED_ATTRIBUTE_REFERENCE',
   431→              message: `Category "${categoryName}" references undefined attribute: "${attributeName}"`,
   432→              path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
   433→              severity: 'error',
   434→              category: 'reference',
   435→              suggestion: `Define attribute "${attributeName}" in attributes.schema or remove the reference`,
   436→            });
   437→          }
   438→        }
   439→      }
   440→    }
   441→
   442→    // Check for orphaned attributes (defined but not used in any category)
   443→    const usedAttributes = new Set<string>();
   444→    for (const [categoryName, categoryConfig] of Object.entries(config.processingConfig.attributeRelevance)) {
   445→      if (categoryName === '_roles_legend' || categoryName === 'RolesLegend') continue;
   446→      // Type guard to ensure we have the correct structure
   447→      if (typeof categoryConfig === 'object' && categoryConfig !== null && 'categoryRoles' in categoryConfig) {
   448→        if (categoryConfig.categoryRoles) {
   449→          Object.keys(categoryConfig.categoryRoles).forEach((attr) => usedAttributes.add(attr));
   450→        }
   451→      }
   452→    }
   453→
   454→    // Determine if this is a minimal/incomplete config
   455→    // A config is minimal if it's missing either top-level categories OR category signals
   456→    // UNLESS it has rule-based classification defined in subtypes
   457→    const hasTopLevelCategories =
   458→      config.processingConfig.topLevelCategories && Object.keys(config.processingConfig.topLevelCategories).length > 0;
   459→    const hasCategorySignals =
   460→      config.processingConfig.categorySignals && Object.keys(config.processingConfig.categorySignals).length > 0;
   461→
   462→    // Check if config has rule-based classification (makes it non-minimal even without signals)
   463→    let hasRuleBasedClassification = false;
   464→    if (hasTopLevelCategories) {
   465→      for (const category of Object.values(config.processingConfig.topLevelCategories)) {
   466→        for (const subtype of Object.values(category.subtypes)) {
   467→          if (subtype.ruleBasedClassification) {
   468→            hasRuleBasedClassification = true;
   469→            break;
   470→          }
   471→        }
   472→        if (hasRuleBasedClassification) break;
   473→      }
   474→    }
   475→
   476→    const isMinimalConfig = (!hasTopLevelCategories || !hasCategorySignals) && !hasRuleBasedClassification;
   477→
   478→    for (const attributeName of Array.from(definedAttributes)) {
   479→      totalChecks++;
   480→      if (!usedAttributes.has(attributeName)) {
   481→        // For minimal configs, orphaned attributes are errors (incomplete matrix)
   482→        // For complete configs, orphaned attributes are warnings (quality issue)
   483→        if (isMinimalConfig) {
   484→          errors.push({
   485→            code: 'INCOMPLETE_ATTRIBUTE_MATRIX',
   486→            message: `Attribute "${attributeName}" is defined but not used in any category`,
   487→            path: `attributes.schema.${attributeName}`,
   488→            severity: 'error',
   489→            category: 'reference',
   490→            suggestion: 'Remove unused attribute from schema or add to category relevance matrix',
   491→          });
   492→        } else {
   493→          warnings.push({
   494→            code: 'ORPHANED_ATTRIBUTE',
   495→            message: `Attribute "${attributeName}" is defined but not used in any category`,
   496→            path: `attributes.schema.${attributeName}`,
   497→            impact: 'low',
   498→            recommendation: 'Consider removing unused attributes or adding them to relevance matrix',
   499→          });
   500→        }
   501→      }
   502→    }
   503→
   504→    return { errors, warnings, totalChecks };
   505→  }
   506→
   507→  private async validatePerformanceSettings(config: CategoryConfiguration): Promise<{
   508→    warnings: ValidationWarning[];
   509→  }> {
   510→    const warnings: ValidationWarning[] = [];
   511→
   512→    // Skip if topLevelCategories is not defined
   513→    if (!config.processingConfig?.topLevelCategories) {
   514→      return { warnings };
   515→    }
   516→
   517→    // Check for performance optimization opportunities
   518→    const totalRules = this.countRules(config);
   519→    if (totalRules > 1000) {
   520→      warnings.push({
   521→        code: 'HIGH_RULE_COUNT',
   522→        message: `Configuration has ${totalRules} rules, which may impact performance`,
   523→        path: 'topLevelCategories',
   524→        impact: 'medium',
   525→        recommendation: 'Consider optimizing rules or enabling rule compilation',
   526→      });
   527→    }
   528→
   529→    const totalCategories = Object.keys(config.processingConfig.topLevelCategories).length;
   530→    if (totalCategories > 20) {
   531→      warnings.push({
   532→        code: 'HIGH_CATEGORY_COUNT',
   533→        message: `Configuration has ${totalCategories} categories, which may impact classification performance`,
   534→        path: 'topLevelCategories',
   535→        impact: 'medium',
   536→        recommendation: 'Consider consolidating related categories',
   537→      });
   538→    }
   539→
   540→    return { warnings };
   541→  }
   542→
   543→  private async validateSecuritySettings(config: CategoryConfiguration): Promise<{
   544→    errors: ValidationError[];
   545→    warnings: ValidationWarning[];
   546→  }> {
   547→    const errors: ValidationError[] = [];
   548→    const warnings: ValidationWarning[] = [];
   549→
   550→    // Skip if topLevelCategories is not defined
   551→    if (!config.processingConfig?.topLevelCategories) {
   552→      return { errors, warnings };
   553→    }
   554→
   555→    // Check for potentially dangerous regex patterns
   556→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   557→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   558→        if (subtype.ruleBasedClassification) {
   559→          for (const [tier, rules] of Object.entries(subtype.ruleBasedClassification)) {
   560→            if (rules) {
   561→              for (const rule of rules) {
   562→                if (rule.operation === 'regexAny' && rule.values) {
   563→                  for (const pattern of rule.values) {
   564→                    if (this.isDangerousRegex(pattern)) {
   565→                      warnings.push({
   566→                        code: 'DANGEROUS_REGEX_PATTERN',
   567→                        message: `Potentially dangerous regex pattern in ${categoryName}.${subtypeName}.${tier}: "${pattern}"`,
   568→                        path: `topLevelCategories.${categoryName}.subtypes.${subtypeName}.ruleBasedClassification.${tier}`,
   569→                        impact: 'high',
   570→                        recommendation: 'Review regex pattern for potential ReDoS vulnerability',
   571→                      });
   572→                    }
   573→                  }
   574→                }
   575→              }
   576→            }
   577→          }
   578→        }
   579→      }
   580→    }
   581→
   582→    return { errors, warnings };
   583→  }
   584→
   585→  private async validateConfigurationQuality(config: CategoryConfiguration): Promise<ValidationWarning[]> {
   586→    const warnings: ValidationWarning[] = [];
   587→
   588→    // Skip if topLevelCategories is not defined
   589→    if (!config.processingConfig?.topLevelCategories) {
   590→      return warnings;
   591→    }
   592→
   593→    // Check for empty categories
   594→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   595→      if (Object.keys(category.subtypes).length === 0) {
   596→        warnings.push({
   597→          code: 'EMPTY_CATEGORY',
   598→          message: `Category "${categoryName}" has no subtypes defined`,
   599→          path: `topLevelCategories.${categoryName}`,
   600→          impact: 'medium',
   601→          recommendation: 'Add subtypes or remove the empty category',
   602→        });
   603→      }
   604→    }
   605→
   606→    // Check for categories without AI classification
   607→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   608→      if (category.aiFinalClassification && !category.aiFinalClassification.decisionCriteria?.length) {
   609→        warnings.push({
   610→          code: 'MISSING_AI_CRITERIA',
   611→          message: `Category "${categoryName}" has no AI decision criteria`,
   612→          path: `topLevelCategories.${categoryName}.aiFinalClassification`,
   613→          impact: 'medium',
   614→          recommendation: 'Add decision criteria for AI classification fallback',
   615→        });
   616→      }
   617→    }
   618→
   619→    return warnings;
   620→  }
   621→
   622→  private async validateTuningParameters(config: ProcessingConfigTuning): Promise<{
   623→    errors: ValidationError[];
