   644→    // Validate performance settings
   645→    if (config.performanceTuning) {
   646→      const perf = config.performanceTuning;
   647→      if (perf.maxParallelEmails && perf.emailBatchSize) {
   648→        if (perf.maxParallelEmails > perf.emailBatchSize) {
   649→          warnings.push({
   650→            code: 'INEFFICIENT_PARALLEL_SETTINGS',
   651→            message: 'maxParallelEmails exceeds emailBatchSize',
   652→            path: 'performanceTuning',
   653→            impact: 'medium',
   654→            recommendation: 'Set maxParallelEmails <= emailBatchSize for optimal batching',
   655→          });
   656→        }
   657→      }
   658→    }
   659→
   660→    return { errors, warnings };
