   663→  private async validatePerformanceConsistency(config: ProcessingConfigTuning): Promise<ValidationWarning[]> {
   664→    const warnings: ValidationWarning[] = [];
   665→
   666→    // Check for conflicting performance settings
   667→    if (config.performanceTuning?.parallelProcessingEnabled === false) {
   668→      if (config.attributeDetectionTuning?.parallelDetectionEnabled === true) {
   669→        warnings.push({
