   682→  private async validateCrossConfigurationReferences(
   683→    categoryConfig: CategoryConfiguration,
   684→    domainSources: Record<string, string[]>
   685→  ): Promise<ValidationError[]> {
   686→    const errors: ValidationError[] = [];
   687→
   688→    // Validate domain references
   689→    const availableDomainGroups = new Set(Object.keys(domainSources));
   690→
   691→    for (const [categoryName, signals] of Object.entries(categoryConfig.processingConfig.categorySignals)) {
   692→      if (signals.hardAssertions?.fromDomainsRef) {
   693→        const groupName = signals.hardAssertions.fromDomainsRef.sourceGroup;
   694→        if (!availableDomainGroups.has(groupName)) {
   695→          errors.push({
   696→            code: 'INVALID_DOMAIN_GROUP_REFERENCE',
   697→            message: `Category "${categoryName}" references undefined domain group: "${groupName}"`,
   698→            path: `categorySignals.${categoryName}.hardAssertions.fromDomainsRef.sourceGroup`,
   699→            severity: 'error',
   700→            category: 'reference',
   701→            suggestion: `Define domain group "${groupName}" in domain sources or update the reference`,
   702→          });
   703→        }
   704→      }
   705→    }
   706→
   707→    return errors;
