   976→              path: `attributes.attributeBonusMap.${categoryName}.${attributeName}`,
   977→              severity: 'error',
   978→              category: 'reference',
   979→              suggestion: `Add "${attributeName}" to attributes.schema or remove from bonus map`,
   980→            });
   981→          }
   982→        }
   983→      }
   984→    }
   985→
   986→    // Check attribute relevance matrix completeness
   987→    if (config.processingConfig.attributeRelevance) {
   988→      for (const [categoryName, relevance] of Object.entries(config.processingConfig.attributeRelevance)) {
   989→        if (categoryName === 'RolesLegend') continue;
   990→
   991→        const categoryRoles = (relevance as { categoryRoles?: Record<string, string> }).categoryRoles;
   992→        if (categoryRoles) {
   993→          for (const attributeName of Object.keys(categoryRoles)) {
