  describe('Low Confidence Routing', () => {
    it('should skip AI for very low confidence scores (<3)', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'uncategorized',
          confidence: 2.1,
          score: 2.1,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'needsReview',
          selectionRationale: 'Very low confidence classification',
        },
      ];
      result.candidateScores = {
        uncategorized: { score: 2.1, confidence: 2.1, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('likely unclassifiable');
    });

    it('should skip AI for scores below AI routing threshold but above low threshold', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'systemNotifications',
          confidence: 6.5,
          score: 6.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'serviceStatus',
          selectionRationale: 'Below AI routing threshold',
        },
      ];
      result.candidateScores = {
        systemNotifications: { score: 6.5, confidence: 6.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');
    });
