import { z } from 'zod';

/**
 * Zod schema for ProcessingConfig validation
 * Includes all tuning parameters per ${repoRoot}/docs/SCORING_LOGIC.md throughout
 */

// Base validation schemas
const PositiveNumberSchema = z.number().min(0);
const ProbabilitySchema = z.number().min(0).max(1);
const WeightSchema = z.number().min(0).max(2);
// const IntegerSchema = z.number().int(); // Reserved for future use
const PositiveIntegerSchema = z.number().int().min(1);

// Tuning parameter schemas for individual stages
const HardAssertionTuningSchema = z.object({
  highConfidenceFloor: ProbabilitySchema.default(0.9),
  domainConfidenceBoost: z.number().min(0).max(0.2).default(0.1),
  subjectPrefixBoost: z.number().min(0).max(0.15).default(0.1),
  fromAddressBoost: z.number().min(0).max(0.1).default(0.05),
  parallelProcessingEnabled: z.boolean().default(true),
});

const StrongIndicatorTuningSchema = z.object({
  baseSeedValue: ProbabilitySchema.default(0.6),
  diminishingReturns: z.object({
    enabled: z.boolean().default(true),
    decayFactor: z.number().min(0.1).max(0.9).default(0.8),
    maxIndicators: PositiveIntegerSchema.default(5),
    minimumValueThreshold: z.number().min(0).max(0.1).default(0.05),
  }),
  domainWeightMultiplier: WeightSchema.default(1.2),
  contentWeightMultiplier: WeightSchema.default(1.0),
  parallelSeedingEnabled: z.boolean().default(true),
});

const RuleScoringTuningSchema = z.object({
  // Subtype scoring formula parameters (KHigh, KMedium, KLow)
  KHigh: PositiveNumberSchema.default(1.0),
  KMedium: PositiveNumberSchema.default(0.7),
  KLow: PositiveNumberSchema.default(0.3),

  // Bounded aggregation parameters
  aggregationCap: ProbabilitySchema.default(1.0),
  diminishingFactor: z.number().min(0.5).max(1.0).default(0.9),

  // Rule evaluation settings
  lexicalPatternWeight: WeightSchema.default(1.0),
  subtypeRuleWeight: WeightSchema.default(1.0),
  caseSensitivity: z.boolean().default(false),
  wordBoundaryMatching: z.boolean().default(true),

  // Performance optimization
  parallelRuleEvaluation: z.boolean().default(true),
  maxParallelRules: PositiveIntegerSchema.default(10),
  ruleCacheEnabled: z.boolean().default(true),
  cacheSizeLimit: PositiveIntegerSchema.default(1000),
});

const AttributeDetectionTuningSchema = z.object({
  // Detection confidence thresholds
  minimumDetectionConfidence: ProbabilitySchema.default(0.7),
  highConfidenceThreshold: ProbabilitySchema.default(0.9),

  // Attribute-specific settings
  selfSentDetection: z.object({
    enabled: z.boolean().default(true),
    confidenceBoost: z.number().min(0).max(0.2).default(0.1),
    domainWhitelist: z.array(z.string()).default([]),
  }),

  domainResolution: z.object({
    enabled: z.boolean().default(true),
    cacheEnabled: z.boolean().default(true),
    cacheTtlSeconds: PositiveIntegerSchema.default(3600),
    timeoutMs: PositiveIntegerSchema.default(5000),
  }),

  contextFlags: z.object({
    urgencyDetectionEnabled: z.boolean().default(true),
    structuralPatternDetection: z.boolean().default(true),
    temporalSignalDetection: z.boolean().default(true),
  }),

  // Parallel processing
  parallelDetectionEnabled: z.boolean().default(true),
  maxParallelDetectors: PositiveIntegerSchema.default(5),
  detectorTimeoutMs: PositiveIntegerSchema.default(10000),
});

const AttributeInfluenceTuningSchema = z.object({
  // Bonus and penalty application
  bonusMultiplier: WeightSchema.default(1.0),
  penaltyMultiplier: WeightSchema.default(1.0),

  // Influence caps per role type
  coreAttributeMaxInfluence: ProbabilitySchema.default(0.4),
  primaryBoostMaxInfluence: ProbabilitySchema.default(0.3),
  secondaryBoostMaxInfluence: ProbabilitySchema.default(0.2),
  disambiguatorMaxInfluence: ProbabilitySchema.default(0.15),
  filterMaxInfluence: ProbabilitySchema.default(0.1),

  // Total influence limits
  maxTotalBonus: ProbabilitySchema.default(0.5),
  maxTotalPenalty: ProbabilitySchema.default(0.3),

  // Role enforcement
  strictRoleEnforcement: z.boolean().default(true),
  fallbackToNeutralOnConflict: z.boolean().default(true),

  // Parallel processing
  parallelInfluenceCalculation: z.boolean().default(true),
  influenceCacheEnabled: z.boolean().default(true),
});

const DisambiguationTuningSchema = z.object({
  // Pairwise adjustment thresholds
  confidenceGapThreshold: ProbabilitySchema.default(0.1),
  minimumAdjustmentThreshold: z.number().min(0).max(0.1).default(0.02),
  maximumAdjustmentPerPair: ProbabilitySchema.default(0.2),

  // Adjustment limits
  maxAdjustmentsPerCategory: PositiveIntegerSchema.default(3),
  totalAdjustmentCap: ProbabilitySchema.default(0.3),

  // Disambiguation strategies
  pairwiseAdjustmentsEnabled: z.boolean().default(true),
  contextAwareDisambiguation: z.boolean().default(true),
  temporalDisambiguation: z.boolean().default(false),

  // Performance settings
  maxDisambiguationIterations: PositiveIntegerSchema.default(5),
  convergenceThreshold: z.number().min(0).max(0.01).default(0.001),
});

const MultiLabelTuningSchema = z.object({
  // Selection thresholds
  minSecondaryConfidence: ProbabilitySchema.default(0.6),
  maxConfidenceSum: PositiveNumberSchema.default(2.0),

  // Label limits
  maxLabels: PositiveIntegerSchema.default(3),
  maxTopLevelLabels: PositiveIntegerSchema.default(2),

  // Co-presence rules
  financialActionableCopresenceAllowed: z.boolean().default(false),
  categoryCombinationPenalties: z.record(z.string(), z.number().min(0).max(0.5)).default({}),
  strictCombinationMode: z.boolean().default(false),

  // Quality controls
  minimumPrimaryLead: ProbabilitySchema.default(0.1),
  secondaryConfidenceDecay: z.number().min(0.5).max(1.0).default(0.9),
  labelCoherenceCheck: z.boolean().default(true),
});

const AIRoutingTuningSchema = z.object({
  // Routing thresholds
  highConfidenceThreshold: ProbabilitySchema.default(0.8),
  aiRequiredThreshold: ProbabilitySchema.default(0.4),
  manualReviewThreshold: ProbabilitySchema.default(0.2),

  // AI service configuration
  modelSettings: z.object({
    primaryModel: z.string().default('gpt-4'),
    fallbackModel: z.string().default('gpt-3.5-turbo'),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: PositiveIntegerSchema.default(500),
    timeoutMs: PositiveIntegerSchema.default(30000),
  }),

  // Batch processing
  batchSize: PositiveIntegerSchema.default(10),
  batchTimeoutMs: PositiveIntegerSchema.default(60000),
  parallelAiRequests: z.boolean().default(true),
  maxParallelRequests: PositiveIntegerSchema.default(5),

  // Skip conditions
  skipAiConditions: z
    .array(
      z.enum([
        'highConfidenceAchieved',
        'singleStrongCategory',
        'hardAssertionMatch',
        'manualReviewFlagged',
        'processingTimeExceeded',
      ])
    )
    .default([]),

  // Quality controls
  aiConfidenceThreshold: ProbabilitySchema.default(0.7),
  consistencyCheckEnabled: z.boolean().default(true),
  fallbackToRuleBased: z.boolean().default(true),
});

const AuditTrailTuningSchema = z.object({
  // Explainability trace configuration
  generateFullTrace: z.boolean().default(true),
  includeStageTimings: z.boolean().default(true),
  includeParallelExecutionMap: z.boolean().default(true),
  includeConfigurationRefs: z.boolean().default(true),

  // Trace detail levels
  ruleEvaluationDetails: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  attributeDetectionDetails: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  scoreBreakdownPrecision: PositiveIntegerSchema.default(4),

  // Performance optimization
  traceCompressionEnabled: z.boolean().default(false),
  asyncTraceWriting: z.boolean().default(true),
  traceBatchingEnabled: z.boolean().default(true),
  batchSize: PositiveIntegerSchema.default(50),

  // Retention settings
  traceRetentionDays: PositiveIntegerSchema.default(90),
  archiveOldTraces: z.boolean().default(true),
  compressionAfterDays: PositiveIntegerSchema.default(30),
});

// Performance and parallelism settings
const PerformanceTuningSchema = z.object({
  // Global parallel processing
  parallelProcessingEnabled: z.boolean().default(true),
  maxParallelEmails: PositiveIntegerSchema.default(10),
  emailBatchSize: PositiveIntegerSchema.default(50),

  // Stage-specific parallelism
  parallelStages: z
    .array(
      z.enum(['attributeDetection', 'ruleEvaluation', 'influenceCalculation', 'aiRouting', 'auditTrailGeneration'])
    )
    .default(['attributeDetection', 'ruleEvaluation']),

  // Memory management
  memoryLimitMb: PositiveIntegerSchema.default(512),
  gcThresholdMb: PositiveIntegerSchema.default(256),
  cacheSizeLimits: z.object({
    ruleCacheMb: PositiveIntegerSchema.default(64),
    attributeCacheMb: PositiveIntegerSchema.default(32),
    configCacheMb: PositiveIntegerSchema.default(16),
  }),

  // Timeout settings
  totalProcessingTimeoutMs: PositiveIntegerSchema.default(60000),
  stageTimeoutMs: PositiveIntegerSchema.default(10000),
  databaseTimeoutMs: PositiveIntegerSchema.default(5000),

  // Optimization flags
  enableCaching: z.boolean().default(true),
  enableMemoization: z.boolean().default(true),
  enableLazyLoading: z.boolean().default(true),
  precompileRules: z.boolean().default(true),
});

// Main processing configuration schema with all tuning parameters
export const ProcessingConfigTuningSchema = z.object({
  // Global settings
  version: PositiveIntegerSchema,
  schemaVersion: z.string().default('1.0.0'),
  taxonomyNotes: z.string(),

  // Stage-specific tuning parameters
  hardAssertionTuning: HardAssertionTuningSchema.optional(),
  strongIndicatorTuning: StrongIndicatorTuningSchema.optional(),
  ruleScoringTuning: RuleScoringTuningSchema.optional(),
  attributeDetectionTuning: AttributeDetectionTuningSchema.optional(),
  attributeInfluenceTuning: AttributeInfluenceTuningSchema.optional(),
  disambiguationTuning: DisambiguationTuningSchema.optional(),
  multiLabelTuning: MultiLabelTuningSchema.optional(),
  aiRoutingTuning: AIRoutingTuningSchema.optional(),
  auditTrailTuning: AuditTrailTuningSchema.optional(),

  // Performance and system tuning
  performanceTuning: PerformanceTuningSchema.optional(),

  // Validation settings
  strictValidation: z.boolean().default(true),
  allowExperimentalFeatures: z.boolean().default(false),
  compatibilityMode: z.enum(['strict', 'permissive', 'legacy']).default('strict'),

  // Monitoring and debugging
  monitoring: z
    .object({
      enableMetricsCollection: z.boolean().default(true),
      detailedTiming: z.boolean().default(false),
      memoryTracking: z.boolean().default(false),
      errorTracking: z.boolean().default(true),
      performanceAlerts: z
        .object({
          slowProcessingThresholdMs: PositiveIntegerSchema.default(30000),
          highMemoryThresholdMb: PositiveIntegerSchema.default(256),
          errorRateThreshold: ProbabilitySchema.default(0.05),
        })
        .default({}),
    })
    .default({}),
});

// Simplified schema for basic processing config (backward compatibility)
export const BasicProcessingConfigSchema = z.object({
  version: PositiveIntegerSchema,
  taxonomyNotes: z.string(),

  // Essential settings only
  settings: z.object({
    initialization: z.object({
      applyHardAssertions: z.boolean().default(true),
      seedCategoryScores: z.boolean().default(true),
    }),
    ruleScoring: z.object({
      useLexicalPatterns: z.boolean().default(true),
      applySubtypeRules: z.boolean().default(true),
      boundedAggregation: z.boolean().default(true),
    }),
    attributeProcessing: z.object({
      detectSelfSent: z.boolean().default(true),
      resolveDomains: z.boolean().default(true),
      deriveContextFlags: z.boolean().default(true),
    }),
    disambiguation: z.object({
      pairwiseAdjustments: z.boolean().default(true),
      confidenceGapThreshold: ProbabilitySchema.default(0.1),
    }),
    multiLabelSelection: z.object({
      maxLabels: PositiveIntegerSchema.default(3),
      minSecondaryConfidence: ProbabilitySchema.default(0.6),
    }),
    aiRouting: z.object({
      highConfidenceThreshold: ProbabilitySchema.default(0.8),
      aiRequiredThreshold: ProbabilitySchema.default(0.4),
    }),
  }),

  // Basic performance settings
  performance: z
    .object({
      parallelProcessing: z.boolean().default(true),
      batchSize: PositiveIntegerSchema.default(50),
      timeoutMs: PositiveIntegerSchema.default(60000),
    })
    .default({}),
});

// Type inference
export type ProcessingConfigTuning = z.infer<typeof ProcessingConfigTuningSchema>;
export type BasicProcessingConfig = z.infer<typeof BasicProcessingConfigSchema>;
export type HardAssertionTuning = z.infer<typeof HardAssertionTuningSchema>;
export type StrongIndicatorTuning = z.infer<typeof StrongIndicatorTuningSchema>;
export type RuleScoringTuning = z.infer<typeof RuleScoringTuningSchema>;
export type AttributeDetectionTuning = z.infer<typeof AttributeDetectionTuningSchema>;
export type AttributeInfluenceTuning = z.infer<typeof AttributeInfluenceTuningSchema>;
export type DisambiguationTuning = z.infer<typeof DisambiguationTuningSchema>;
export type MultiLabelTuning = z.infer<typeof MultiLabelTuningSchema>;
export type AIRoutingTuning = z.infer<typeof AIRoutingTuningSchema>;
export type AuditTrailTuning = z.infer<typeof AuditTrailTuningSchema>;
export type PerformanceTuning = z.infer<typeof PerformanceTuningSchema>;

// Validation helper functions
export const validateProcessingConfigTuning = (config: unknown): ProcessingConfigTuning => {
  return ProcessingConfigTuningSchema.parse(config);
};

export const validateBasicProcessingConfig = (config: unknown): BasicProcessingConfig => {
  return BasicProcessingConfigSchema.parse(config);
};

// Tuning parameter validation helpers
export const validateHardAssertionTuning = (tuning: unknown): HardAssertionTuning => {
  return HardAssertionTuningSchema.parse(tuning);
};

export const validateRuleScoringTuning = (tuning: unknown): RuleScoringTuning => {
  return RuleScoringTuningSchema.parse(tuning);
};

export const validateAttributeInfluenceTuning = (tuning: unknown): AttributeInfluenceTuning => {
  return AttributeInfluenceTuningSchema.parse(tuning);
};

export const validatePerformanceTuning = (tuning: unknown): PerformanceTuning => {
  return PerformanceTuningSchema.parse(tuning);
};

// Configuration validation utilities
export const isValidProcessingConfig = (config: unknown): boolean => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getProcessingConfigErrors = (config: unknown): string[] => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

// Default configurations for different use cases
export const getDefaultProductionConfig = () => ({
