  },
  monitoring: {
    enableMetricsCollection: true,
    detailedTiming: true,
    memoryTracking: true,
    errorTracking: true,
  },
  strictValidation: true,
  allowExperimentalFeatures: true,
});

export const getDefaultTestingConfig = () => ({
  performanceTuning: {
    parallelProcessingEnabled: false,
    maxParallelEmails: 1,
    emailBatchSize: 5,
    enableCaching: false,
    totalProcessingTimeoutMs: 180000,
  },
  monitoring: {
    enableMetricsCollection: false,
    detailedTiming: true,
    memoryTracking: false,
    errorTracking: true,
  },
  strictValidation: true,
  allowExperimentalFeatures: true,
  compatibilityMode: 'permissive' as const,
});

