private async validateTuningParameters(config: ProcessingConfigTuning): Promise<{
  errors: ValidationError[];
  warnings: ValidationWarning[];
}> {
  const errors: ValidationError[] = [];
  const warnings: ValidationWarning[] = [];

  // Validate AI routing threshold relationships
  // REQUIRED ORDERING: manualReviewThreshold < aiRequiredThreshold < highConfidenceThreshold
  if (config.aiRoutingTuning) {
    const ai = config.aiRoutingTuning;

    // Check: low < aiRequired
    if (ai.manualReviewThreshold !== undefined && ai.manualReviewThreshold >= ai.aiRequiredThreshold) {
      errors.push({
        code: 'INVALID_AI_ROUTING_THRESHOLD_ORDER',
        message: `AI routing threshold ordering violation: manualReviewThreshold (${ai.manualReviewThreshold}) must be < aiRequiredThreshold (${ai.aiRequiredThreshold})`,
        path: 'aiRoutingTuning.manualReviewThreshold',
        severity: 'error',
        category: 'logic',
        suggestion: `Set manualReviewThreshold < aiRequiredThreshold. Suggested: manualReviewThreshold = ${Math.max(0, ai.aiRequiredThreshold - 0.2).toFixed(1)}`,
      });
    }

    // Check: aiRequired < high
    if (ai.aiRequiredThreshold >= ai.highConfidenceThreshold) {
      errors.push({
        code: 'INVALID_AI_ROUTING_THRESHOLD_ORDER',
        message: `AI routing threshold ordering violation: aiRequiredThreshold (${ai.aiRequiredThreshold}) must be < highConfidenceThreshold (${ai.highConfidenceThreshold})`,
        path: 'aiRoutingTuning.aiRequiredThreshold',
        severity: 'error',
        category: 'logic',
        suggestion: `Set aiRequiredThreshold < highConfidenceThreshold. Suggested: aiRequiredThreshold = ${Math.max(0.3, ai.highConfidenceThreshold - 0.3).toFixed(1)}`,
      });
    }

    // Validate threshold ranges are reasonable (warn if too close together)
    if (
      ai.manualReviewThreshold !== undefined &&
      ai.aiRequiredThreshold - ai.manualReviewThreshold < 0.1
    ) {
      warnings.push({
        code: 'AI_ROUTING_THRESHOLDS_TOO_CLOSE',
        message: `aiRequiredThreshold (${ai.aiRequiredThreshold}) is very close to manualReviewThreshold (${ai.manualReviewThreshold}) - may limit medium confidence range`,
        path: 'aiRoutingTuning',
        impact: 'medium',
        recommendation: 'Consider spacing thresholds at least 0.1-0.2 apart for better classification granularity',
      });
    }

    if (ai.highConfidenceThreshold - ai.aiRequiredThreshold < 0.2) {
      warnings.push({
        code: 'AI_ROUTING_THRESHOLDS_TOO_CLOSE',
        message: `highConfidenceThreshold (${ai.highConfidenceThreshold}) is very close to aiRequiredThreshold (${ai.aiRequiredThreshold}) - may limit medium confidence range`,
        path: 'aiRoutingTuning',
        impact: 'medium',
        recommendation: 'Consider spacing thresholds at least 0.2-0.3 apart for better AI routing decisions',
      });
    }
  }

