  describe('Threshold Validation and Ordering', () => {
    it('should use correct threshold ordering (low < aiRequired < high)', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);

      // Test low confidence threshold (3)
      result.selectedLabels = [
        {
          category: 'uncategorized',
          confidence: 2.5,
          score: 2.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'needsReview',
          selectionRationale: 'Below low confidence threshold',
        },
      ];
      result.candidateScores = {
        uncategorized: { score: 2.5, confidence: 2.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');

      // Test AI required threshold (12)
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 13.0,
          score: 13.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Above AI required threshold',
        },
      ];
      result.candidateScores = {
        financial: { score: 13.0, confidence: 13.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');

      // Test high confidence threshold (15)
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 16.0,
          score: 16.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Above high confidence threshold',
        },
      ];
      result.candidateScores = {
        financial: { score: 16.0, confidence: 16.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('High confidence');
    });

    it('should correctly apply medium confidence range logic', () => {
      // Test score in medium range but below aiRequiredThreshold
      const result1 = createClassificationResult('test-123', 'session-123', 0);
      result1.selectedLabels = [
        {
          category: 'systemNotifications',
          confidence: 7.0, // Between lowConfidence (3) and aiRequiredThreshold (12)
          score: 7.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'serviceStatus',
          selectionRationale: 'Medium confidence below AI routing threshold',
        },
      ];
      result1.candidateScores = {
        systemNotifications: { score: 7.0, confidence: 7.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result1, mockConfig);
      expect(result1.needsAiClassification).toBe(false);
      expect(result1.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');

      // Test score in medium range above aiRequiredThreshold
      const result2 = createClassificationResult('test-123', 'session-123', 0);
      result2.selectedLabels = [
        {
          category: 'actionable',
          confidence: 12.5, // Between aiRequiredThreshold (12) and highConfidence (15)
          score: 12.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'implicitAction',
          selectionRationale: 'Medium confidence above AI routing threshold',
        },
      ];
      result2.candidateScores = {
        actionable: { score: 12.5, confidence: 12.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result2, mockConfig);
      expect(result2.needsAiClassification).toBe(true);
      expect(result2.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result2.explainabilityTrace.aiRouting?.reason).toContain('AI classification can improve accuracy');
    });

    it('should include threshold values in explainability trace', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 10.0,
          score: 10.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Test threshold documentation',
        },
      ];
      result.candidateScores = {
        financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Verify threshold values are recorded in explainability trace
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);

      // Verify routing decision is documented
      expect(result.explainabilityTrace.aiRouting?.reason).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.reason).not.toBe('');
    });
  });
});

